css:
/* Tour demo deck styles */
.slide { font-family: 'Segoe UI', system-ui, -apple-system, sans-serif; padding: 60px; box-sizing: border-box; width: 100%; height: 100%; display: flex; flex-direction: column; justify-content: center; }
.slide h1 { font-size: 2.8em; font-weight: 700; margin: 0 0 16px 0; line-height: 1.2; }
.slide h2 { font-size: 1.8em; font-weight: 600; margin: 0 0 12px 0; line-height: 1.3; }
.slide p { font-size: 1.15em; line-height: 1.7; margin: 0 0 12px 0; color: #374151; }
.slide ul { list-style: none; padding: 0; margin: 16px 0; }
.slide ul li { padding: 10px 0 10px 32px; position: relative; font-size: 1.1em; line-height: 1.6; color: #374151; }
.slide ul li::before { content: ''; position: absolute; left: 0; top: 18px; width: 10px; height: 10px; border-radius: 50%; }
.title-slide { background: linear-gradient(135deg, #1e40af 0%, #7c3aed 100%); color: white; text-align: center; justify-content: center; align-items: center; }
.title-slide h1 { font-size: 3.2em; color: white; text-shadow: 0 2px 8px rgba(0,0,0,0.15); }
.title-slide p { color: rgba(255,255,255,0.9); font-size: 1.3em; max-width: 600px; }
.content-slide { background: #ffffff; }
.content-slide h2 { color: #1e40af; border-bottom: 3px solid #3b82f6; padding-bottom: 8px; display: inline-block; }
.content-slide ul li::before { background: #3b82f6; }
.outlook-slide { background: linear-gradient(135deg, #f0f9ff 0%, #ede9fe 100%); }
.outlook-slide h2 { color: #7c3aed; border-bottom: 3px solid #8b5cf6; padding-bottom: 8px; display: inline-block; }
.outlook-slide ul li::before { background: #8b5cf6; }
.badge { display: inline-block; background: rgba(255,255,255,0.2); padding: 8px 20px; border-radius: 20px; font-size: 0.85em; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 24px; }
